import{_ as a,o as t,c as o,ae as i}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Journeys on Accelerated Mobile Pages (AMP)","description":"","frontmatter":{"title":"Journeys on Accelerated Mobile Pages (AMP)","slug":"journeys-via-amp"},"headers":[],"relativePath":"developer-hub/journeys-via-amp.md","filePath":"developer-hub/journeys-via-amp.md"}'),n={name:"developer-hub/journeys-via-amp.md"};function r(s,e,l,d,u,c){return t(),o("div",null,[...e[0]||(e[0]=[i(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><a href="https://www.ampproject.org/" target="_blank" rel="noreferrer">Accelerated Mobile Pages (AMP)</a> are a way to build pages that serve static content so that they load in Google search results much faster. Google uses AMP to quickly serve content on mobile devices without users having to click through to a website to view the content, and AMP pages often appear at the top of mobile search results.</p><p>AMP pages by design make it difficult for users to go anywhere except back to Google search, and difficult for you to convert users to your website or your app. With AMP-compatible Journeys, you can convert mobile web traffic from Google search results to your app and take advantage of extra traffic from AMP pages. Select Journeys templates can be shown on your AMP-compatible website.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>To host AMP Journeys and show in Google search as an AMP page, your webpage must be <a href="https://www.ampproject.org/docs/" target="_blank" rel="noreferrer">AMP</a>-compatible.</li><li>Journeys uses your alternate domain for Universal Links. Make sure you include your <code>xxxx-alternate.app.link</code> domain in your <a href="https://help.branch.io/developers-hub/docs/ios-basic-integration#3-configure-associated-domains" target="_blank" rel="noreferrer">Associated Domains</a>.</li></ul><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><ol><li>Add the Branch AMP SDK to your site. The AMP SDK consists of 2-3 snippets that you can insert into your AMP page. Add the following snippet between the AMP page’s <code>&lt;&gt;</code> tags:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;style amp-custom&gt;#branch-amp-journey{bottom:0;left:0;width:100%;height:77px;position:fixed;}.hideme{width:100%;height:77px;left:24px;background-color:none;position:fixed;}.close{width:24px;height:100%;left:0;z-index:10000;background-color:none;position:fixed;}.branch-amp-journey-inner{position:relative;width:100%;height:100%;z-index:9999;}.donotdisplay{display:none;}&lt;/style&gt;</span></span></code></pre></div><ol start="2"><li>Modify the following snippet by replacing <code>DOMAIN_HERE</code> with your <code>xxxx.app.link</code> Branch Link domain (<em>do not use a custom subdomain</em>), and <code>BRANCH_KEY_HERE</code> with your Branch API key - in both the <code>amp-list</code> tag and the <code>amp-iframe</code> tag. You can find these in <a href="https://dashboard.branch.io/link-settings" target="_blank" rel="noreferrer">Link Settings</a> and <a href="https://dashboard.branch.io/account-settings" target="_blank" rel="noreferrer">Account Settings</a>.</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;amp-list tabindex=0 role=&quot;&quot; on=&quot;tap:branch-amp-journey.hide&quot; id=&quot;branch-amp-journey&quot; src=&quot;https://DOMAIN-HERE/branch-amp-journeys-pre?branch_key=BRANCH_KEY_HERE&amp;__aj_cid=CLIENT_ID(_s)&amp;__amp_viewer=VIEWER&amp;__aj_source_url=SOURCE_URL&amp;__aj_canonical_url=CANONICAL_URL&amp;__aj_v=1.0.0&quot; layout=fixed-height height=&quot;77px&quot;&gt;&lt;template type=&quot;amp-mustache&quot; id=&quot;journey-template&quot;&gt;&lt;a class=&quot;close&quot; on=&quot;tap:branch-amp-journey.hide&quot;&gt;&lt;/a&gt;&lt;div class=&quot;hideme&quot; &gt;&lt;/div&gt;&lt;amp-iframe class=&quot;branch-amp-journey-inner {{do_not_display}}&quot; layout=&quot;fixed-height&quot; height=&quot;77px&quot; resizable src=&quot;https://DOMAIN-HERE/branch-amp-journeys?branch_key=BRANCH_KEY_HERE&amp;__aj_cid={{__aj_cid}}&amp;__aj_source_url={{__aj_source_url}}&amp;__aj_canonical_url={{__aj_canonical_url}}&amp;_audience_rule_id={{_audience_rule_id}}&amp;_branch_view_id={{_branch_view_id}}&amp;__aj_v=1.0.0&quot; sandbox=&quot;allow-scripts allow-top-navigation allow-same-origin&quot; frameborder=&quot;0&quot;&gt;&lt;div overflow&gt;&lt;/div&gt;&lt;/amp-iframe&gt;&lt;/template&gt;&lt;/amp-list&gt;</span></span></code></pre></div><ol start="3"><li>From there, add the modified snippet between the <code>&lt;&gt;</code> tags of your AMP page, preferably near or at the bottom.</li><li>Lastly, if you do not already have the following AMP scripts on your page, add them between the AMP page&#39;s <code>&lt;&gt;</code> tags:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;script async src=&quot;https://cdn.ampproject.org/v0/amp-list-0.1.js&quot; custom-element=&quot;amp-list&quot;&gt;&lt;/script&gt;&lt;script async src=&quot;https://cdn.ampproject.org/v0/amp-mustache-0.1.js&quot; custom-template=&quot;amp-mustache&quot;&gt;&lt;/script&gt;&lt;script async src=&quot;https://cdn.ampproject.org/v0/amp-iframe-0.1.js&quot; custom-element=&quot;amp-iframe&quot;&gt;&lt;/script&gt;</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Include canonical URL for SEO and deep linking</p><p><a href="https://www.ampproject.org/docs/guides/discovery" target="_blank" rel="noreferrer">Google recommends</a> that on your AMP page, you include a reference to the canonical URL of the non-AMP page with the same content. For example, you should include a tag like this in the <code>&lt;&gt;</code> section of your AMP page: . This helps make your AMP page discoverable, and likely helps ensure that SEO information is shared between these two pages. Additionally, Branch automatically embeds the canonical URL in the Journey link data, leading to better identification of content and the ability to use this key for deep linking.</p></div><h2 id="create-a-journey-that-targets-amp-web-in-your-audience" tabindex="-1">Create a Journey That Targets AMP Web in Your Audience <a class="header-anchor" href="#create-a-journey-that-targets-amp-web-in-your-audience" aria-label="Permalink to &quot;Create a Journey That Targets AMP Web in Your Audience&quot;">​</a></h2><h3 id="_1-select-audience" tabindex="-1">1. Select Audience <a class="header-anchor" href="#_1-select-audience" aria-label="Permalink to &quot;1. Select Audience&quot;">​</a></h3><ol><li><p>AMP Journeys can be created as part of the normal <a href="https://help.branch.io/using-branch/docs/create-journey-banner-or-interstitial#1-select-audience" target="_blank" rel="noreferrer">Journeys creation flow</a>. You can target users on AMP pages by checking the box <strong>AMP Web</strong> on the Select Audience step:</p></li><li><p>Click <strong>Save &amp; Continue</strong> to configure your Journeys template and views.</p></li></ol><h3 id="_2-configure-views" tabindex="-1">2. Configure Views <a class="header-anchor" href="#_2-configure-views" aria-label="Permalink to &quot;2. Configure Views&quot;">​</a></h3><ol><li>When you click <strong>Select Template</strong> from the <strong>Configure Views</strong> step, the <strong>standard bottom banner</strong> view type should already be selected. This is currently the only template supported on AMP because Google requires that banners not show in the top 75% of an AMP page.</li><li>Hover over the template and click <strong>Create</strong>.</li><li>Customize the template and click <strong>Save &amp; Continue</strong> when you&#39;re done.</li></ol><h3 id="_3-validate-test" tabindex="-1">3. Validate &amp; Test <a class="header-anchor" href="#_3-validate-test" aria-label="Permalink to &quot;3. Validate &amp; Test&quot;">​</a></h3><ol><li>On the <strong>Validate &amp; Test</strong> phase, you will see AMP-specific messages if you have targeted <strong>AMP Web</strong> users on the <a href="./journeys-via-amp.html#targeting-audiences-with-a-url">Select Audience</a> step.</li></ol><h2 id="error-messages-troubleshooting" tabindex="-1">Error Messages &amp; Troubleshooting <a class="header-anchor" href="#error-messages-troubleshooting" aria-label="Permalink to &quot;Error Messages &amp; Troubleshooting&quot;">​</a></h2><ul><li><strong>The selected template is not AMP-compatible</strong>: If Branch has detected that you have selected a template that is not compatible with AMP, you will see an error on the <strong>Validate &amp; Test</strong> step.</li><li><a href="./troubleshoot-journey-app-banners.html">Reference this guide for more information on troubleshooting and error messages on Journeys.</a></li></ul><h2 id="advanced-configurations-for-amp-journeys" tabindex="-1">Advanced Configurations for AMP Journeys <a class="header-anchor" href="#advanced-configurations-for-amp-journeys" aria-label="Permalink to &quot;Advanced Configurations for AMP Journeys&quot;">​</a></h2><h3 id="targeting-audiences-with-a-url" tabindex="-1">Targeting Audiences with a URL <a class="header-anchor" href="#targeting-audiences-with-a-url" aria-label="Permalink to &quot;Targeting Audiences with a URL&quot;">​</a></h3><p>With AMP, Google will serve your page from the Google AMP cache. This means that the URL that serves your AMP page will look something like <code>https://www.google.com/amp/s/www.example.com/amp/doc.html</code>. However, Branch passes through your original source URL, and this is what you should use for audience targeting. For the advanced audience filter <strong>Is viewing a page URL</strong>, you&#39;ll want to use the original URL where you host the AMP page. In this example, that would be <code>https://www.example.com/amp/doc.html</code>.</p><h3 id="deep-linking-with-amp" tabindex="-1">Deep linking with AMP <a class="header-anchor" href="#deep-linking-with-amp" aria-label="Permalink to &quot;Deep linking with AMP&quot;">​</a></h3><p>You can configure links with deep link data on AMP in two ways:</p><ol><li>Add query parameters to your Branch Link in the AMP SDK</li><li>Add deep link data to a Journey in the dashboard</li></ol><div class="info custom-block"><p class="custom-block-title">Use $canonical_url for deep linking</p><p>AMP Journeys, along with regular Journeys and the Short Link Creator, automatically embeds <code>$canonical_url</code> in your link data based on meta tags on your web or AMP page. If you use this key to route to specific content in your app, you do not have to add anything extra for AMP.</p></div><h4 id="add-query-parameters-in-the-amp-sdk" tabindex="-1">Add query parameters in the AMP SDK <a class="header-anchor" href="#add-query-parameters-in-the-amp-sdk" aria-label="Permalink to &quot;Add query parameters in the AMP SDK&quot;">​</a></h4><p>To deep link to specific content in your app, you can add query parameters to your Branch Link within the <code>amp-iframe</code>. Here is what the <code>amp-iframe</code> looks like without any query parameters:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;amp-iframe class=&quot;branch-amp-journey-inner {{do_not_display}}&quot; layout=&quot;fixed-height&quot; height=&quot;77px&quot; resizable src=&quot;https://DOMAIN-HERE/branch-amp-journeys?branch_key=BRANCH_KEY_HERE&amp;__aj_cid={{__aj_cid}}&amp;__aj_source_url={{__aj_source_url}}&amp;__aj_canonical_url={{__aj_canonical_url}}&amp;_audience_rule_id={{_audience_rule_id}}&amp;_branch_view_id={{_branch_view_id}}&amp;__aj_v=1.0.0&quot; sandbox=&quot;allow-scripts allow-top-navigation allow-same-origin&quot; frameborder=&quot;0&quot;&gt;&lt;div overflow&gt;&lt;/div&gt;&lt;/amp-iframe&gt;</span></span></code></pre></div><p>If your deep linking keys were <strong>productId</strong> and <strong>category</strong>, for example, you would add <code>&amp;productId=1234&amp;category=shoes</code> to your <code>amp-iframe</code> like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;amp-iframe class=&quot;branch-amp-journey-inner {{do_not_display}}&quot; layout=&quot;fixed-height&quot; height=&quot;77px&quot; resizable src=&quot;https://DOMAIN-HERE/branch-amp-journeys?branch_key=BRANCH_KEY_HERE&amp;__aj_cid={{__aj_cid}}&amp;__aj_source_url={{__aj_source_url}}&amp;__aj_canonical_url={{__aj_canonical_url}}&amp;_audience_rule_id={{_audience_rule_id}}&amp;_branch_view_id={{_branch_view_id}}&amp;__aj_v=1.0.0&amp;productId=1234&amp;category=shoes&quot; sandbox=&quot;allow-scripts allow-top-navigation allow-same-origin&quot; frameborder=&quot;0&quot;&gt;&lt;div overflow&gt;&lt;/div&gt;&lt;/amp-iframe&gt;</span></span></code></pre></div><p>If you are generating AMP pages programmatically, it makes sense to generate these keys as query params at the same time.</p><h4 id="dynamic-layout-customization" tabindex="-1">Dynamic layout customization <a class="header-anchor" href="#dynamic-layout-customization" aria-label="Permalink to &quot;Dynamic layout customization&quot;">​</a></h4><p>You can customize the appearance of a Journey dynamically using query parameters on your <code>amp-iframe</code> link. These are the fields currently supported for dynamic layout customization on AMP:</p><table tabindex="0"><thead><tr><th><strong>Link Data Key</strong></th><th><strong>Value</strong></th><th><strong>Example</strong></th></tr></thead><tbody><tr><td><code>$journeys_button_get_has_app</code></td><td>The call to action button when the app is currently installed</td><td><code>$journeys_button_get_has_app=Download</code></td></tr><tr><td><code>$journeys_button_get_no_app</code></td><td>The call to action button when the app is <strong>not</strong> currently installed</td><td><code>$journeys_button_get_no_app=Read</code></td></tr><tr><td><code>$journeys_description</code></td><td>This is the description or subtitle in the frame</td><td><code>$journeys_description=Continue+reading+in+the+app.</code></td></tr></tbody></table><h4 id="add-deep-link-data-in-the-journeys-dashboard" tabindex="-1">Add deep link data in the Journeys dashboard <a class="header-anchor" href="#add-deep-link-data-in-the-journeys-dashboard" aria-label="Permalink to &quot;Add deep link data in the Journeys dashboard&quot;">​</a></h4><p>You can also add deep link data to a Journey in the dashboard. In the <strong>Customize Template</strong> screen, click the button and add your key:value pairs in the deep link data fields. For example if your deep linking key was <strong>productId</strong>:</p><h2 id="amp-journey-limitations" tabindex="-1">AMP Journey Limitations <a class="header-anchor" href="#amp-journey-limitations" aria-label="Permalink to &quot;AMP Journey Limitations&quot;">​</a></h2><p>Because javascript is limited on AMP and cookies are restricted on both AMP and iOS, AMP Journeys does not support all of standard Journeys functionality. The following Journeys features are affected:</p><ul><li>Event-based audience rules work within AMP only or after a Branch Link click on an AMP page. <a href="./journeys-via-amp.html#targeting-limitations">Read more</a>.</li><li>Only templates on the bottom of the page and equal to 76px in height show on AMP.</li><li><a href="https://help.branch.io/using-branch/docs/creatives-manager#dismissal-settings" target="_blank" rel="noreferrer">Dismiss period</a> is not supported - after dismiss, Journeys will show again during the next AMP session.</li><li><a href="https://help.branch.io/using-branch/docs/journeys-faqs#client-side-javascript-controls-faqs" target="_blank" rel="noreferrer">Client-side JavaScript controls</a> are not supported.</li><li>Auto-opening the app with open_app: true is not supported.</li><li><a href="https://help.branch.io/using-branch/docs/advanced-journeys-configuration#setup-via-web-sdk" target="_blank" rel="noreferrer">Deep linking with setBranchViewData</a> is not supported.</li><li><a href="https://help.branch.io/developers-hub/docs/web-advanced-features#include-deep-link-data-in-html" target="_blank" rel="noreferrer">Branch-hosted deep link data</a> will not be scraped.</li><li>If your site uses a template engine like Jinja that looks for and replaces liquid tags (ex: {{ yourObject }}), then you should confirm that it does not remove Branch tags on render. For Jinja specifically, you should wrap the Branch code on your AMP page with raw tags:</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{% raw %}</span></span>
<span class="line"><span>&lt;amp-list tabindex=0 role=&quot;&quot; on=&quot;tap:branch-amp-journey.hide&quot; id=&quot;branch-amp-journey&quot; src=&quot;https://DOMAIN-HERE/branch-amp-journeys-pre?branch_key=BRANCH_KEY_HERE&amp;_aj_cid=CLIENT_ID(_s)&amp;amp_viewer=VIEWER&amp;aj_source_url=SOURCE_URL&amp;aj_canonical_url=CANONICAL_URL&amp;aj_v=1.0.0&quot; layout=fixed-height height=&quot;77px&quot;&gt;&lt;template type=&quot;amp-mustache&quot; id=&quot;journey-template&quot;&gt;&lt;a class=&quot;close&quot; on=&quot;tap:branch-amp-journey.hide&quot;&gt;&lt;/a&gt;&lt;div class=&quot;hideme&quot; &gt;&lt;/div&gt;&lt;amp-iframe class=&quot;branch-amp-journey-inner do_not_display&quot; layout=&quot;fixed-height&quot; height=&quot;77px&quot; resizable src=&quot;https://DOMAIN-HERE/branch-amp-journeys?branch_key=BRANCH_KEY_HERE&amp;aj_cid=aj_cid&amp;aj_source_url=aj_source_url&amp;aj_canonical_url=aj_canonical_url&amp;_audience_rule_id=_audience_rule_id&amp;_branch_view_id=_branch_view_id&amp;_aj_v=1.0.0&quot; sandbox=&quot;allow-scripts allow-top-navigation allow-same-origin&quot; frameborder=&quot;0&quot;&gt;&lt;div overflow&gt;&lt;/div&gt;&lt;/amp-iframe&gt;&lt;/template&gt;&lt;/amp-list&gt;</span></span>
<span class="line"><span>{% endraw %}</span></span></code></pre></div><h3 id="targeting-limitations" tabindex="-1">Targeting Limitations <a class="header-anchor" href="#targeting-limitations" aria-label="Permalink to &quot;Targeting Limitations&quot;">​</a></h3><p>Because cookies are restricted on both AMP and iOS, event-based audience rules on AMP Journeys are cookie-restricted. Practically, this means that targeting works <em>only within AMP</em> for the following rules:</p><ul><li>Has completed event</li><li>Has visited web</li><li>Has visited the app</li><li>Has the app installed</li></ul><p>Once a user has clicked a Branch Link outside of AMP, event-based audience rules will adhere to the regular web cookie for that user, and will work across AMP and non-AMP web.</p><h3 id="banner-limitations" tabindex="-1">Banner Limitations <a class="header-anchor" href="#banner-limitations" aria-label="Permalink to &quot;Banner Limitations&quot;">​</a></h3><p>For the time being, only banners of a fixed height and placement (bottom of the page) are compatible with AMP. This includes <strong>Branch Banner Bottom</strong>, or other custom banners with page placement on the bottom of the page and height of 76px.</p>`,50)])])}const m=a(n,[["render",r]]);export{h as __pageData,m as default};
